import{_ as t,o as r,c as e,a2 as i}from"./chunks/framework.VxKNwi4m.js";const c=JSON.parse('{"title":"회의 관리 (Meetings)","description":"","frontmatter":{},"headers":[],"relativePath":"work-manage/meeting.md","filePath":"work-manage/meeting.md","lastUpdated":1781775222000}'),o={name:"work-manage/meeting.md"};function l(n,a,s,h,g,d){return r(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="회의-관리-meetings" tabindex="-1">회의 관리 (Meetings) <a class="header-anchor" href="#회의-관리-meetings" aria-label="Permalink to &quot;회의 관리 (Meetings)&quot;">​</a></h1><p>회의 관리 모듈은 팀 프로젝트나 본사 차원에서 진행되는 각종 회의의 기록을 체계적으로 관리하고, 논의된 내용을 기반으로 업무(Task)를 생성하거나 연결하는 기능을 제공합니다.</p><h2 id="_1-개요-및-접근-방법" tabindex="-1">1. 개요 및 접근 방법 <a class="header-anchor" href="#_1-개요-및-접근-방법" aria-label="Permalink to &quot;1. 개요 및 접근 방법&quot;">​</a></h2><p>회의 관리 메뉴는 두 가지 방식으로 접근할 수 있습니다.</p><ul><li><strong>본사 회의</strong>: 상단 메인 메뉴의 [회의]를 통해 접근하며, 회사 본사 차원의 전체 회의 목록을 조회합니다.</li><li><strong>프로젝트 회의</strong>: 특정 프로젝트 선택 후 프로젝트 내 [회의] 메뉴를 통해 접근하며, 해당 프로젝트에 귀속된 회의만 필터링하여 조회합니다.</li></ul><h2 id="_2-회의록-목록-및-검색" tabindex="-1">2. 회의록 목록 및 검색 <a class="header-anchor" href="#_2-회의록-목록-및-검색" aria-label="Permalink to &quot;2. 회의록 목록 및 검색&quot;">​</a></h2><p>회의록 목록에서는 등록된 모든 회의의 제목, 일시, 카테고리, 상태 및 담당자 정보를 한눈에 확인할 수 있습니다.</p><ul><li><strong>카테고리 필터</strong>: 우측 사이드바를 통해 특정 범주(예: 주간 회의, 기술 미팅 등)별로 회의를 필터링할 수 있습니다.</li><li><strong>검색 기능</strong>: 제목이나 내용을 키워드로 검색하여 필요한 회의록을 빠르게 찾을 수 있습니다.</li><li><strong>상태 표시</strong>: &#39;준비중&#39;, &#39;완료됨&#39;, &#39;취소됨&#39; 등 회의의 진행 상태가 칩(Chip) 형태로 표시됩니다.</li></ul><h2 id="_3-회의록-작성-및-수정" tabindex="-1">3. 회의록 작성 및 수정 <a class="header-anchor" href="#_3-회의록-작성-및-수정" aria-label="Permalink to &quot;3. 회의록 작성 및 수정&quot;">​</a></h2><p>새 회의록을 작성하거나 기존 기록을 수정할 때 다음과 같은 상세 항목을 입력할 수 있습니다.</p><h3 id="기본-정보" tabindex="-1">기본 정보 <a class="header-anchor" href="#기본-정보" aria-label="Permalink to &quot;기본 정보&quot;">​</a></h3><ul><li><strong>제목</strong>: 회의의 명칭을 입력합니다. (필수)</li><li><strong>카테고리</strong>: 회의의 성격에 맞는 범주를 선택합니다.</li><li><strong>회의 일시</strong>: 회의가 진행되는(또는 진행된) 날짜와 시간을 선택합니다.</li><li><strong>상태</strong>: 현재 회의의 진행 상태를 설정합니다.</li></ul><h3 id="회의-내용-markdown-지원" tabindex="-1">회의 내용 (Markdown 지원) <a class="header-anchor" href="#회의-내용-markdown-지원" aria-label="Permalink to &quot;회의 내용 (Markdown 지원)&quot;">​</a></h3><ul><li><strong>회의 의제</strong>: 회의에서 논의할 주요 의제를 미리 공유하기 위해 입력합니다.</li><li><strong>회의 내용</strong>: 회의 진행 과정을 상세히 기록합니다. 마크다운 에디터를 통해 서식 있는 문서 작성이 가능합니다.</li><li><strong>결정 사항</strong>: 회의를 통해 확정된 합의 내용을 별도로 기록하여 강조할 수 있습니다.</li><li><strong>조치 사항</strong>: 회의 이후 진행되어야 할 후속 작업(To-Do)을 기록합니다.</li></ul><h3 id="참석자-및-파일" tabindex="-1">참석자 및 파일 <a class="header-anchor" href="#참석자-및-파일" aria-label="Permalink to &quot;참석자 및 파일&quot;">​</a></h3><ul><li><strong>참석자</strong>: 시스템 사용자를 참석자 목록에서 다중 선택할 수 있습니다.</li><li><strong>기타 참석자</strong>: 외부 인원 등 시스템 계정이 없는 참석자를 텍스트로 기록합니다.</li><li><strong>첨부 파일</strong>: 회의 관련 문서, 발표 자료 등을 여러 개 첨부할 수 있습니다.</li></ul><h2 id="_4-회의-상세-보기-및-업무-연동" tabindex="-1">4. 회의 상세 보기 및 업무 연동 <a class="header-anchor" href="#_4-회의-상세-보기-및-업무-연동" aria-label="Permalink to &quot;4. 회의 상세 보기 및 업무 연동&quot;">​</a></h2><p>등록된 회의록의 상세 화면에서는 작성된 모든 내용과 첨부 파일을 확인할 수 있으며, 특히 <strong>업무(Issue) 관리</strong>와의 강력한 연동 기능을 제공합니다.</p><h3 id="관련-업무-task-관리" tabindex="-1">관련 업무(Task) 관리 <a class="header-anchor" href="#관련-업무-task-관리" aria-label="Permalink to &quot;관련 업무(Task) 관리&quot;">​</a></h3><p>회의 중 결정된 사항이나 조치 사항을 실제 시스템상의 &#39;업무&#39;로 바로 등록하고 관리할 수 있습니다.</p><ul><li><strong>관련 업무 추가</strong>: 회의 상세 페이지 하단의 [관련 업무 추가] 버튼을 통해 해당 회의와 연결된 새 업무를 즉시 생성합니다.</li><li><strong>업무 상태 확인</strong>: 연결된 모든 업무의 현재 진행 상태와 담당자를 회의록 상세 페이지에서 실시간으로 확인할 수 있습니다.</li><li><strong>업무 상세 이동</strong>: 연결된 업무 번호나 제목을 클릭하면 해당 업무의 상세 페이지로 바로 이동합니다.</li></ul><h3 id="수정-및-삭제" tabindex="-1">수정 및 삭제 <a class="header-anchor" href="#수정-및-삭제" aria-label="Permalink to &quot;수정 및 삭제&quot;">​</a></h3><ul><li>작성자 또는 관리 권한이 있는 사용자는 회의록을 수정하거나 삭제할 수 있습니다.</li><li>회의록 수정 화면에서도 연결된 업무들을 개별적으로 수정할 수 있는 기능을 제공합니다.</li></ul><h2 id="_5-활동-기록-activity-log-연동" tabindex="-1">5. 활동 기록(Activity Log) 연동 <a class="header-anchor" href="#_5-활동-기록-activity-log-연동" aria-label="Permalink to &quot;5. 활동 기록(Activity Log) 연동&quot;">​</a></h2><p>회의록의 생성, 수정 등의 모든 활동은 프로젝트의 [실행 기록] 탭에 자동으로 기록됩니다. 다른 팀원들은 실행 기록 목록에서 회의 의제의 요약 내용을 미리 확인하고 상세 페이지로 접근할 수 있습니다.</p>',25)])])}const m=t(o,[["render",l]]);export{c as __pageData,m as default};
